    public static void main(String[] args) {
        HashPerformance hp = new HashPerformance();
        int N = 10000;
        List<Integer> list = new ArrayList<>();
        Set<Integer>  set  = new HashSet<>();
        for (int i = 0; i < N; i++) { list.add(i); set.add(i); }

        // Search for last element (worst case for linear)
        long t1 = System.nanoTime();
        for (int i = 0; i < 1000; i++) hp.linearContains(list, N-1);
        long linearTime = System.nanoTime() - t1;

